mapper.select:
/* com.shop.mapper.frontWeb.display.selectProductInfoListForEnumPaging */ SELECT TP.ID AS prodId , TP.PROD_NM AS prodNm , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , FD.SYS_FILE_NM AS sysFileNm FROM TB_PRODUCT TP LEFT JOIN TB_FILE_DET FD ON FD.FILE_ID = TP.REP_FILE_ID AND FD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND TP.ID > #{filter.lastProdId}
ORDER BY TP.ID LIMIT #{pageRowCount} + 1;
